import React from "react";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { AuthProvider, useAuth } from "./AuthContext";

import LoginPage from "./components/LoginPage/LoginPage";
import DashboardPage from "./components/DashboardPage/DashboardPage";
import PriceManagementPage from "./components/PriceManagementPage/PriceManagementPage";
import InventoryMonitoringPage from "./components/InventoryMonitoringPage/InventoryMonitoringPage";
import ReportsAndAnalyticsPage from "./components/ReportsAndAnalyticsPage/ReportsAndAnalyticsPage";
import AlertsManagementPage from "./components/AlertsManagement/AlertsManagementPage";
import UserManagementPage from "./components/UserManagementPage/UserManagementPage";
import HelpCenterPage from "./components/HelpCenterPage/HelpCenterPage";

const ProtectedRoute = ({ children }: { children: JSX.Element }) => {
    const { isAuthenticated } = useAuth();
    return isAuthenticated ? children : <Navigate to="/" />;
};

function App() {
    return (
        <AuthProvider>
            <BrowserRouter>
                <Routes>
                    <Route path="/" element={<LoginPage />} />
                    <Route
                        path="/dashboard"
                        element={<ProtectedRoute><DashboardPage /></ProtectedRoute>}
                    />
                    <Route
                        path="/prices"
                        element={<ProtectedRoute><PriceManagementPage /></ProtectedRoute>}
                    />
                    <Route
                        path="/inventory"
                        element={<ProtectedRoute><InventoryMonitoringPage /></ProtectedRoute>}
                    />
                    <Route
                        path="/reports"
                        element={<ProtectedRoute><ReportsAndAnalyticsPage /></ProtectedRoute>}
                    />
                    <Route
                        path="/alerts"
                        element={<ProtectedRoute><AlertsManagementPage /></ProtectedRoute>}
                    />
                    <Route
                        path="/users"
                        element={<ProtectedRoute><UserManagementPage /></ProtectedRoute>}
                    />
                    <Route
                        path="/help"
                        element={<ProtectedRoute><HelpCenterPage /></ProtectedRoute>}
                    />
                </Routes>
            </BrowserRouter>
        </AuthProvider>
    );
}

export default App;
